<?php
declare(strict_types=1);
if($path!=='/bookings/team-calendars')return;
require_permission('bookings.edit');$calendarId=(int)($_GET['calendar_id']??post('calendar_id'));if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='members'){db()->prepare('DELETE FROM booking_calendar_members WHERE calendar_id=?')->execute([$calendarId]);$q=db()->prepare('INSERT INTO booking_calendar_members(calendar_id,user_id,weight) VALUES(?,?,?)');foreach((array)post('members',[]) as $uid)$q->execute([$calendarId,(int)$uid,max(1,(int)((array)post('weights',[]))[$uid]??1)]);audit('update','booking_calendar_members',$calendarId);}elseif($action==='exception'){$start=new DateTimeImmutable((string)post('starts_at'));$end=new DateTimeImmutable((string)post('ends_at'));if($end<=$start)flash('error','End time must follow start time.');else{db()->prepare('INSERT INTO booking_availability_exceptions(calendar_id,user_id,starts_at,ends_at,reason,created_by) VALUES(?,?,?,?,?,?)')->execute([$calendarId,(int)post('user_id'),$start->format('Y-m-d H:i:s'),$end->format('Y-m-d H:i:s'),trim((string)post('reason')),user()['id']]);audit('create','booking_availability_exception',(int)db()->lastInsertId());}}elseif($action==='delete_exception')db()->prepare('DELETE FROM booking_availability_exceptions WHERE id=? AND calendar_id=?')->execute([(int)post('exception_id'),$calendarId]);redirect('/bookings/team-calendars?calendar_id='.$calendarId);}$calendars=db()->query('SELECT * FROM booking_calendars ORDER BY name')->fetchAll();if(!$calendarId&&$calendars)$calendarId=(int)$calendars[0]['id'];$users=db()->query("SELECT id,COALESCE(NULLIF(display_name,''),username) name FROM users WHERE active=1 ORDER BY name")->fetchAll();$q=db()->prepare('SELECT user_id,weight FROM booking_calendar_members WHERE calendar_id=?');$q->execute([$calendarId]);$members=array_column($q->fetchAll(),'weight','user_id');$q=db()->prepare("SELECT x.*,COALESCE(NULLIF(u.display_name,''),u.username) user_name FROM booking_availability_exceptions x JOIN users u ON u.id=x.user_id WHERE x.calendar_id=? AND x.ends_at>=NOW() ORDER BY x.starts_at");$q->execute([$calendarId]);$exceptions=$q->fetchAll();layout('Team calendar members',function()use($calendars,$calendarId,$users,$members,$exceptions){?><div class="actions"><h1 style="margin:0">Team calendar members</h1><span class="spacer"></span><a class="btn secondary" href="/bookings/calendars">Booking calendars</a></div><form class="card" method="get"><label>Calendar<select name="calendar_id" onchange="this.form.submit()"><?php foreach($calendars as $c):?><option value="<?=$c['id']?>" <?=$calendarId==$c['id']?'selected':''?>><?=e($c['name'].' · '.$c['calendar_type'])?></option><?php endforeach?></select></label></form><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="members"><input type="hidden" name="calendar_id" value="<?=$calendarId?>"><h2>Members and round-robin weight</h2><div class="checkboxes"><?php foreach($users as $u):?><label><input type="checkbox" name="members[]" value="<?=$u['id']?>" <?=isset($members[$u['id']])?'checked':''?>><?=e($u['name'])?> <input style="width:75px" type="number" min="1" name="weights[<?=$u['id']?>]" value="<?=e($members[$u['id']]??1)?>" title="Assignment weight"></label><?php endforeach?></div><button>Save members</button></form><form class="card form-grid" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="exception"><input type="hidden" name="calendar_id" value="<?=$calendarId?>"><h2 class="full">Out of office / blocked time</h2><label>User<select name="user_id"><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></label><label>Starts<input type="datetime-local" name="starts_at" required></label><label>Ends<input type="datetime-local" name="ends_at" required></label><label>Reason<input name="reason"></label><button>Add blocked time</button></form><div class="card"><h2>Upcoming blocked time</h2><table><tbody><?php foreach($exceptions as $x):?><tr><td><?=e($x['user_name'])?></td><td><?=e($x['starts_at'])?> – <?=e($x['ends_at'])?></td><td><?=e($x['reason'])?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="delete_exception"><input type="hidden" name="calendar_id" value="<?=$calendarId?>"><input type="hidden" name="exception_id" value="<?=$x['id']?>"><button class="danger compact">Remove</button></form></td></tr><?php endforeach?></tbody></table></div><?php });exit;
